import { Component } from '@angular/core';
import { }
@Component({
  selector: 'app-new-record',
  templateUrl: './new-record.component.html',
  styleUrls: ['./new-record.component.css'],
})
export class NewRecordComponent {
  concepto: string = '';
  observaciones: string = '';
  cantidad: number = 0;
  tipoOpciones = ['gasto', 'ingreso'];
  tipo: string = '';

  constructor(
    private csvgeneratorService csvgeneratorService;
  ) {}

  btnCrear() {
    console.log('Btn crear');
    console.log(this.concepto, this.observaciones, this.cantidad, this.tipo);

    if (this.isValidInput()) {
      console.log('Valid inputs');
    }
  }

  isValidInput(): boolean {
    return this.concepto != '' && 
    this.concepto != ''  && 
    this.concepto != ''  &&
    this.tipoOpciones.includes(this.tipo);
    ;
  }
}
